#include <iostream>
#include <vector>
#include <utility>

class Solution {
public:
  std::vector<int> dfs(std::vector<std::vector<int>>& graph) {
    std::vector<int> visited;
    function<void(int)> dfsHelper = [&](int node) {
      visited.push_back(node);
      for (int neighbor : graph[node]) {
        dfsHelper(neighbor);
      }
    };
    dfsHelper(0);
    std::reverse(visited.begin(), visited.end());
    return visited;
  }
};

int main() {
  Solution solution;
  std::vector<std::vector<int>> graph = {{1, 2, 3}, {0, 3}, {0, 2}, {1, 0}};
  auto result = solution.dfs(graph);
  for (int node : result) {
    std::cout << node << '\n';
  }
  return 0;
}
